CREATE TRIGGER LG_ORFLINE_INS_099_02 ON LG_099_02_ORFLINE
FOR INSERT
AS
DECLARE @LINETYPE       SMALLINT
DECLARE @STOCKREF       INT
DECLARE @VARIANTREF     INT
DECLARE @AMOUNT         FLOAT
DECLARE @SHIPPEDAMOUNT  FLOAT
DECLARE @UINFO1         FLOAT
DECLARE @UINFO2         FLOAT
DECLARE @DT             DATETIME
DECLARE @DORESERVE      SMALLINT
DECLARE @RESERVEDT      DATETIME
DECLARE @CLOSED         SMALLINT
DECLARE @STATUS         SMALLINT
DECLARE @TRCODE         SMALLINT
DECLARE @SOURCEINDEX    SMALLINT
DECLARE @OFFTRREF       INT
DECLARE @OFFREF         INT
DECLARE @PREVLNREF      INT
DECLARE @DETLN          SMALLINT
DECLARE @PREVLNNO       SMALLINT
DECLARE @COEF           SMALLINT
DECLARE @CLREF          INT
DECLARE @REMAMOUNT      FLOAT
DECLARE @new_Status     SMALLINT
DECLARE @new_Trcode     SMALLINT
DECLARE @new_LINENET    FLOAT
DECLARE @new_REPORTRATE FLOAT
DECLARE @new_BILLED     SMALLINT
DECLARE @_Closed     SMALLINT
DECLARE @VATSTATE     SMALLINT
DECLARE @STRANS      SMALLINT
DECLARE @PROMOTION   SMALLINT
DECLARE @COMPOSITE   SMALLINT
DECLARE @SERVICE     SMALLINT
DECLARE @LCLASS      SMALLINT
DECLARE @VALID       SMALLINT
DECLARE @CANCELL     SMALLINT
DECLARE @AFFECTCOLLTRL SMALLINT
DECLARE @AFFECTRISK SMALLINT
DECLARE @WITHPAYTRANS SMALLINT
DECLARE @DEVIR       SMALLINT
SELECT  @STRANS    = 0,
        @PROMOTION = 1,
        @SERVICE   = 4,
        @COMPOSITE = 6,
        @LCLASS    = 10
SELECT @LINETYPE      = I.LINETYPE,
       @STOCKREF      = I.STOCKREF,
       @VARIANTREF    = I.VARIANTREF,
       @AMOUNT        = I.AMOUNT,
       @SHIPPEDAMOUNT = I.SHIPPEDAMOUNT,
       @UINFO1        = I.UINFO1,
       @UINFO2        = I.UINFO2,
       @DT            = I.DATE_,
       @DORESERVE     = I.DORESERVE,
       @RESERVEDT     = I.RESERVEDATE,
       @CLOSED        = I.CLOSED,
       @CANCELL       = I.CANCELLED,
       @STATUS        = I.STATUS,
       @TRCODE        = I.TRCODE,
       @VATSTATE      = I.VATINC,
       @SOURCEINDEX   = I.SOURCEINDEX,
       @OFFTRREF      = I.OFFTRANSREF,
       @OFFREF        = I.OFFERREF,
       @PREVLNREF     = I.PREVLINEREF,
       @DETLN         = I.DETLINE,
       @PREVLNNO      = I.PREVLINENO,
       @AFFECTCOLLTRL = I.AFFECTCOLLATRL,
       @AFFECTRISK    = I.AFFECTRISK,
       @WITHPAYTRANS  = I.WITHPAYTRANS,
       @DEVIR         = I.DEVIR    FROM INSERTED I
IF @CANCELL=1
 BEGIN
  SELECT @CLOSED = 1
 END
EXECUTE LG_UPDATE_ORDTRANS_099_02 @LINETYPE, @STOCKREF, @VARIANTREF, @AMOUNT, @SHIPPEDAMOUNT, @UINFO1, @UINFO2,
                                  @DT, @DORESERVE, @RESERVEDT, @CLOSED, @STATUS, @TRCODE, @SOURCEINDEX,
                                  @OFFTRREF, @OFFREF, @PREVLNREF, @DETLN, @PREVLNNO, 1, @DEVIR
SELECT @VALID = 0
IF    ((@LINETYPE = @STRANS)  OR
       (@LINETYPE = @COMPOSITE) OR (@LINETYPE = @SERVICE) OR (@LINETYPE = @LCLASS))
 SELECT @VALID = 1
SELECT  @REMAMOUNT = I.AMOUNT - I.SHIPPEDAMOUNT - I.SHIPPEDAMNTSUGG, @_Closed=I.CLOSED  FROM INSERTED I
IF @REMAMOUNT<0
 set @REMAMOUNT=0
IF @_Closed=0
BEGIN
SELECT @CLREF = I.CLIENTREF,
       @new_TrCode = I.TRCODE,
       @new_Status = I.STATUS,
       @new_ReportRate = I.REPORTRATE,
       @new_BILLED = I.BILLEDITEM FROM INSERTED I
IF @VALID=1
BEGIN
 SELECT @new_LINENET=(I.LINENET - I.DISTDISC + I.DISTEXP + I.DISTCOST + I.VATAMNT + I.DISTEXPVAT + I.ADDTAXAMOUNT + I.DISTDISCVAT) FROM INSERTED I
 select @new_LINENET = (@new_LINENET/I.AMOUNT)*@REMAMOUNT FROM INSERTED I
END
IF (@LINETYPE <> @PROMOTION) AND (@DETLN = 0) AND (ISNULL(@AFFECTRISK,0)=0) AND (ISNULL(@WITHPAYTRANS,0)=0) AND (@VALID=1)
 EXECUTE LG_UPDATECLCARDRISKNUMS_099_02 @CLREF, @new_TRCODE, @new_LINENET, -1, @new_ReportRate, @new_BILLED, @new_Status, 0, 0
IF (@LINETYPE <> @PROMOTION) AND (@DETLN = 0) AND (@AFFECTCOLLTRL=1)  AND (@VALID=1)
 EXECUTE LG_UPDCOLLATRLRISK_099_02 @CLREF, @new_TRCODE, @new_LINENET, -1, @new_ReportRate, @new_BILLED, @new_Status, 0, 0
END
EXECUTE LG_UPDATEMRPITMCHNG_099 @STOCKREF, @VARIANTREF, @PREVLNREF
